import requests

KONG_ADMIN_URL = 'http://localhost:8001'

def add_service(name, url):
    payload = {
        'name': name,
        'url': url
    }
    response = requests.post(f'{KONG_ADMIN_URL}/services/', json=payload)
    return response.json()

def add_route(service_name, paths):
    payload = {
        'paths': paths
    }
    response = requests.post(f'{KONG_ADMIN_URL}/services/{service_name}/routes', json=payload)
    return response.json()

def add_upstream(name):
    payload = {
        'name': name
    }
    response = requests.post(f'{KONG_ADMIN_URL}/upstreams', json=payload)
    return response.json()

def add_target(upstream_name, target, weight=100):
    payload = {
        'target': target,
        'weight': weight
    }
    response = requests.post(f'{KONG_ADMIN_URL}/upstreams/{upstream_name}/targets', json=payload)
    return response.json()

# Example Usage:
service = add_service('example-service', 'http://example.org')
route = add_route('example-service', ['/example'])
upstream = add_upstream('example-upstream')
target = add_target('example-upstream', '192.168.1.1:80')

print('Service:', service)
print('Route:', route)
print('Upstream:', upstream)
print('Target:', target)